    TORCH_CHECK(A.size(0) == A.size(1) && B.size(0) == B.size(1) && A.size(1) == B.size(0),
                "A and B must be square and of compatible sizes");
    at::Tensor C = at::empty({A.size(0), A.size(1)}, A_in.options().dtype(at::kFloat));
    EXEC_NPU_CMD(aclnnMatmulForLowerTriangularMatricesCustom, A, B, C);
    return C;
}

